-- ============================================================
--  RETAIL BANKING SCHEMA  (PostgreSQL syntax)
--  Hub table: ACCOUNT  (references customer, branch, product)
--
--  Relationship map (account is the centre):
--    customer (1) ──< account >── (1) branch
--                        │  (also referenced by branch ↑)
--                        └── (1) product
--    account (1) ──< card
--    account (1) ──< hist_transactional >── (1) branch
--
--  Load order = parent tables first, then the hub, then children.
-- ============================================================

-- Drop in reverse-dependency order so re-runs are clean
DROP TABLE IF EXISTS hist_transactional CASCADE;
DROP TABLE IF EXISTS card               CASCADE;
DROP TABLE IF EXISTS account            CASCADE;
DROP TABLE IF EXISTS product            CASCADE;
DROP TABLE IF EXISTS branch             CASCADE;
DROP TABLE IF EXISTS customer           CASCADE;

-- ============================================================
-- 1. CUSTOMER  (parent)
-- ============================================================
CREATE TABLE customer (
    cust_id       VARCHAR(10)   PRIMARY KEY,
    name          VARCHAR(100)  NOT NULL,
    address       VARCHAR(200),
    phone_number  VARCHAR(15)   NOT NULL,
    postal_code   VARCHAR(10),
    country       VARCHAR(50),
    email         VARCHAR(100)  UNIQUE,
    father_name   VARCHAR(100),
    mother_name   VARCHAR(100),
    occupation    VARCHAR(100),
    education     VARCHAR(50),
    nationality   VARCHAR(50)   NOT NULL,
    created_date  TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    modified_date TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- ============================================================
-- 2. BRANCH  (parent)
-- ============================================================
CREATE TABLE branch (
    branch_id     VARCHAR(10)   PRIMARY KEY,
    province    VARCHAR(50),
    cluster_name  VARCHAR(50),
    city_name     VARCHAR(50),
    branch_name   VARCHAR(100),
    created_date  TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    modified_date TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- ============================================================
-- 3. PRODUCT  (parent)
-- ============================================================
CREATE TABLE product (
    product_id    VARCHAR(10)   PRIMARY KEY,
    schm_type     VARCHAR(5),
    schm_code     VARCHAR(10),
    product_desc  VARCHAR(100),
    created_date  TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    modified_date TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- ============================================================
-- 4. ACCOUNT  (HUB / main table)
--    FK -> customer, branch, product
-- ============================================================
CREATE TABLE account (
    account_id      VARCHAR(10)   PRIMARY KEY,
    customer_id     VARCHAR(10)   NOT NULL,
    branch_id       VARCHAR(10)   NOT NULL,
    account_balance NUMERIC(15,2) NOT NULL DEFAULT 0.00,
    lien_amt        NUMERIC(15,2) NOT NULL DEFAULT 0.00,
    acct_cls_flg    CHAR(1)       NOT NULL DEFAULT 'N' CHECK (acct_cls_flg IN ('Y','N')),
    product_id      VARCHAR(10)   NOT NULL,
    schm_type       VARCHAR(5),
    schm_code       VARCHAR(10),
    acct_crncy_code VARCHAR(5)    NOT NULL DEFAULT 'NPR',
    acct_opn_date   DATE,
    created_date    TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    modified_date   TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_account_customer FOREIGN KEY (customer_id) REFERENCES customer(cust_id),
    CONSTRAINT fk_account_branch   FOREIGN KEY (branch_id)   REFERENCES branch(branch_id),
    CONSTRAINT fk_account_product  FOREIGN KEY (product_id)  REFERENCES product(product_id)
);

-- ============================================================
-- 5. CARD  (child of account)
-- ============================================================
CREATE TABLE card (
    card_number      VARCHAR(20)   PRIMARY KEY,
    account_id       VARCHAR(10)   NOT NULL,
    balance          NUMERIC(15,2) NOT NULL DEFAULT 0.00,
    card_type        VARCHAR(10)   NOT NULL CHECK (card_type IN ('DEBIT','CREDIT')),
    closing_balance  NUMERIC(15,2),
    card_expiry_date DATE,
    created_date     TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    modified_date    TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_card_account FOREIGN KEY (account_id) REFERENCES account(account_id)
);

-- ============================================================
-- 6. HIST_TRANSACTIONAL  (child of account + branch)
-- ============================================================
CREATE TABLE hist_transactional (
    tran_id         VARCHAR(12)   PRIMARY KEY,
    account_id      VARCHAR(10)   NOT NULL,
    tran_amount     NUMERIC(15,2) NOT NULL CHECK (tran_amount > 0),
    tran_date       DATE          NOT NULL,
    tran_crncy      VARCHAR(5)    NOT NULL,
    branch_id       VARCHAR(10)   NOT NULL,
    tran_particular VARCHAR(15)   NOT NULL CHECK (tran_particular IN ('IN_BRANCH','DIGITAL')),
    tran_remarks    VARCHAR(200),
    created_date    TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    modified_date   TIMESTAMP     NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_hist_account FOREIGN KEY (account_id) REFERENCES account(account_id),
    CONSTRAINT fk_hist_branch  FOREIGN KEY (branch_id)  REFERENCES branch(branch_id)
);

CREATE INDEX idx_tran_date    ON hist_transactional (tran_date);
CREATE INDEX idx_tran_account ON hist_transactional (account_id);

